                current =current[k]            else:
                return Config({}, f"{self._path}.{key}" if self._path else key)
        if isinstance(current, dict):
            return Config(current, f"{self._path}.{key}" if self._path else key)
        return Config({}, f"{self._path}.{key}" if self._path else key)

    def set(self, key: str, value: Any):
        keys = key.split('.')
        current = self._data
        for k in keys[:-1]:            if k not in current:
                current[k] = {}
            current =current[k]        current[keys[-1]] = value

    def update(self, data: dict):
        self._deep_update(self._data, data)

    def to_dict(self) -> dict:
        return self._data

    def __getattr__(self, name: str):
        try:
            return self.get(name)
        except Exception:
            raise AttributeError(f"'Config' object has no attribute '{name}'")

    def _flat_keys(self) -> set:
        keys = set()
        self._collect_keys(self._data, '', keys)
        return keys

    def _collect_keys(self, d: dict, prefix: str, keys: set):
        for k, v in d.items():
            full_key = f"{prefix}.{k}" if prefix else k
            keys.add(full_key)
            if isinstance(v, dict):
                self._collect_keys(v, full_key, keys)

    def _deep_update(self, base: dict, update: dict):
        for k, v in update.items():
